import React, { useState, useEffect, useRef } from "react";
import io from "socket.io-client";
import axios from "axios";
import "./App.css";

const SERVER_URL = process.env.REACT_APP_SERVER_URL || "http://localhost:3001";
const socket = io(SERVER_URL, { transports: ["websocket"] });

function formatTimestamp(dateString) {
  const date = new Date(dateString);
  return date.toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" });
}

function groupMessagesByDate(messages) {
  const groups = {};
  const today = new Date().toDateString();
  for (const msg of messages) {
    const msgDate = new Date(msg.createdAt).toDateString();
    let label = msgDate === today ? "Today" : new Date(msg.createdAt).toLocaleDateString();
    if (!groups[label]) groups[label] = [];
    groups[label].push(msg);
  }
  return groups;
}

function App() {
  const [username, setUsername] = useState(null);
  const [token, setToken] = useState(null);
  const [messages, setMessages] = useState([]);
  const [text, setText] = useState("");
  const [form, setForm] = useState({ username: "", email: "", password: "" });
  const [mode, setMode] = useState("login");

  const [onlineUsers, setOnlineUsers] = useState([]);
  const [typingUser, setTypingUser] = useState(null);
  const [showNewMessages, setShowNewMessages] = useState(false);

  // 🔹 Rooms
  const [rooms, setRooms] = useState(["global"]); // available rooms
  const [currentRoom, setCurrentRoom] = useState("global");
  const [newRoom, setNewRoom] = useState("");

  const [darkMode, setDarkMode] = useState(() => localStorage.getItem("darkMode") === "true");

  const typingTimeoutRef = useRef(null);
  const messagesEndRef = useRef(null);
  const messagesContainerRef = useRef(null);

  // --- Dark mode ---
  useEffect(() => {
    if (darkMode) document.body.classList.add("dark");
    else document.body.classList.remove("dark");
    localStorage.setItem("darkMode", darkMode);
  }, [darkMode]);

  const toggleDarkMode = () => setDarkMode(!darkMode);

  // --- Load user ---
  useEffect(() => {
    const storedUser = localStorage.getItem("chatUser");
    const storedToken = localStorage.getItem("chatToken");
    if (storedUser && storedToken) {
      setUsername(storedUser);
      setToken(storedToken);
      socket.emit("join", { username: storedUser, room: currentRoom });
    }
  }, [currentRoom]);

  // --- Auth ---
  const handleAuth = async (e) => {
    e.preventDefault();
    try {
      const url = `${SERVER_URL}/${mode}`;
      const res = await axios.post(url, form);

      setUsername(res.data.username);
      setToken(res.data.token);
      localStorage.setItem("chatUser", res.data.username);
      localStorage.setItem("chatToken", res.data.token);

      socket.emit("join", { username: res.data.username, room: currentRoom });
    } catch (err) {
      alert(err.response?.data?.error || "Auth failed");
    }
  };

  const handleLogout = () => {
    setUsername(null);
    setToken(null);
    localStorage.removeItem("chatUser");
    localStorage.removeItem("chatToken");
  };

  // --- Load messages ---
  useEffect(() => {
    if (!username) return;
    const fetchMessages = async () => {
      try {
        const res = await axios.get(`${SERVER_URL}/messages/${currentRoom}`);
        setMessages(res.data);
      } catch (err) {
        console.error("Failed to fetch messages:", err);
      }
    };
    fetchMessages();
  }, [username, currentRoom]);

  // --- Socket listeners ---
  useEffect(() => {
    socket.on("receiveMessage", (message) => {
      if (message.room === currentRoom) {
        setMessages((prev) => [...prev, message]);
        if (!isNearBottom()) setShowNewMessages(true);
      }
    });

    socket.on("onlineUsers", (users) => setOnlineUsers(users));
    socket.on("typing", (user) => setTypingUser(user));
    socket.on("stopTyping", () => setTypingUser(null));

    return () => {
      socket.off("receiveMessage");
      socket.off("onlineUsers");
      socket.off("typing");
      socket.off("stopTyping");
    };
  }, [currentRoom]);

  const isNearBottom = () => {
    const container = messagesContainerRef.current;
    if (!container) return true;
    return container.scrollHeight - container.scrollTop - container.clientHeight < 100;
  };

  useEffect(() => {
    if (isNearBottom()) {
      messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
      setShowNewMessages(false);
    }
  }, [messages]);

  const sendMessage = (e) => {
    e.preventDefault();
    if (!text.trim()) return;
    socket.emit("sendMessage", { username, text, room: currentRoom });
    setText("");
    socket.emit("stopTyping", currentRoom);
  };

  const handleTyping = (e) => {
    setText(e.target.value);
    if (username) {
      socket.emit("typing", { username, room: currentRoom });
      if (typingTimeoutRef.current) clearTimeout(typingTimeoutRef.current);
      typingTimeoutRef.current = setTimeout(() => {
        socket.emit("stopTyping", currentRoom);
      }, 1000);
    }
  };

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
    setShowNewMessages(false);
  };

  // --- Add new room ---
  const createRoom = () => {
    if (newRoom.trim() && !rooms.includes(newRoom)) {
      setRooms([...rooms, newRoom]);
      setCurrentRoom(newRoom);
      setNewRoom("");
      socket.emit("join", { username, room: newRoom });
    }
  };

  // --- Render ---
  if (!username) {
    return (
      <div className="app">
        <div className="login">
          <h2>{mode === "login" ? "Login" : "Signup"}</h2>
          <form onSubmit={handleAuth}>
            <input type="text" placeholder="Username"
              value={form.username}
              onChange={(e) => setForm({ ...form, username: e.target.value })} />
            {mode === "signup" && (
              <input type="email" placeholder="Email"
                value={form.email || ""}
                onChange={(e) => setForm({ ...form, email: e.target.value })} />
            )}
            <input type="password" placeholder="Password"
              value={form.password}
              onChange={(e) => setForm({ ...form, password: e.target.value })} />
            <button type="submit">{mode === "login" ? "Login" : "Signup"}</button>
          </form>
          <p>
            {mode === "login" ? "Don't have an account?" : "Already registered?"}{" "}
            <button onClick={() => setMode(mode === "login" ? "signup" : "login")} className="link">
              {mode === "login" ? "Signup" : "Login"}
            </button>
          </p>
        </div>
      </div>
    );
  }

  return (
    <div className="chat-container">
      <div className="chat-header">
        <h2>Welcome, {username} 👋</h2>
        <div>
          <button
            className="toggle-dark"
            onClick={toggleDarkMode}
            data-tooltip={darkMode ? "Switch to Light Mode" : "Switch to Dark Mode"}
          >
            {darkMode ? "☀️ Light" : "🌙 Dark"}
          </button>
          <button className="logout" onClick={handleLogout}>Logout</button>
        </div>
      </div>

      <div className="chat-main">
        {/* Sidebar */}
        <div className="sidebar">
          <h4>Rooms</h4>
          <ul>
            {rooms.map((room, i) => (
              <li key={i}
                style={{ cursor: "pointer", fontWeight: room === currentRoom ? "bold" : "normal" }}
                onClick={() => setCurrentRoom(room)}>
                {room}
              </li>
            ))}
          </ul>
          <input
            type="text"
            value={newRoom}
            onChange={(e) => setNewRoom(e.target.value)}
            placeholder="New room name"
          />
          <button onClick={createRoom}>Create Room</button>

          <h4>Online Users</h4>
          <ul>
            {onlineUsers.map((user, i) => (
              <li key={i}>{user}</li>
            ))}
          </ul>
        </div>

        {/* Messages area */}
        <div className="messages-area">
          <div className="messages" ref={messagesContainerRef}>
            {Object.entries(groupMessagesByDate(messages)).map(([dateLabel, msgs], i) => (
              <div key={i}>
                <div className="date-row"><span className="date-label">{dateLabel}</span></div>
                {msgs.map((msg, j) => {
                  const isMine = msg.username === username;
                  return (
                    <div key={j} className={`message ${isMine ? "me" : "other"}`}>
                      <div className="text">
                        {!isMine && <strong>{msg.username}: </strong>} {msg.text}
                        <span className="timestamp">{formatTimestamp(msg.createdAt)}</span>
                      </div>
                    </div>
                  );
                })}
              </div>
            ))}
            <div ref={messagesEndRef} />
          </div>

          {showNewMessages && (
            <div className="newMessages" onClick={scrollToBottom}>⬇️ New Messages</div>
          )}

          {typingUser && <div className="typing">{typingUser} is typing...</div>}

          <form className="composer" onSubmit={sendMessage}>
            <textarea value={text} onChange={handleTyping} placeholder="Type a message..." />
            <button type="submit">Send</button>
          </form>
        </div>
      </div>
    </div>
  );
}

export default App;
